def validate_decomposition(plan: dict) -> list[str]:
    """
    Validate a decomposition plan. Returns a list of error messages.
    An empty list means the plan is valid.
    """
    errors = []
    sub_tasks = plan.get("sub_tasks", [])
    ids = {t["id"] for t in sub_tasks}

    # Must have at least one sub-task
    if not sub_tasks:
        errors.append("No sub-tasks in decomposition.")

    # Too many sub-tasks is a quality signal
    if len(sub_tasks) > 5:
        errors.append(f"Too many sub-tasks: {len(sub_tasks)} (max 5). Simplify the decomposition.")

    for task in sub_tasks:
        # Required fields
        for field in ("id", "description", "search_query"):
            if not task.get(field):
                errors.append(f"Sub-task {task.get('id', '?')!r} missing field '{field}'.")

        # Dependency references must exist
        for dep in task.get("depends_on", []):
            if dep not in ids:
                errors.append(f"Sub-task {task['id']!r} depends on unknown id {dep!r}.")

    # Detect dependency cycles (topological sort)
    visited = set()
    in_progress = set()

    def has_cycle(task_id):
        if task_id in in_progress:
            return True
        if task_id in visited:
            return False
        in_progress.add(task_id)
        task = next((t for t in sub_tasks if t["id"] == task_id), None)
        if task:
            for dep in task.get("depends_on", []):
                if has_cycle(dep):
                    return True
        in_progress.discard(task_id)
        visited.add(task_id)
        return False

    if any(has_cycle(t["id"]) for t in sub_tasks):
        errors.append("Dependency cycle detected in sub-tasks.")

    if not plan.get("synthesis_instruction"):
        errors.append("Missing synthesis_instruction.")

    return errors

# Usage: retry with a feedback message if validation fails
plan = decompose_task("Compare France and Germany")
errors = validate_decomposition(plan)
if errors:
    print("Invalid decomposition:", errors)
